{
  "name": "Hotel PMS Room Management Dashboard",
  "description": "A functional, professional-grade Hotel Property Management System (PMS) dashboard for room and floor management, following industry standards like Opera/ASI.",
  "requestFramePermissions": []
}

export interface Floor {
  id: string;
  name: string;
}

export interface RoomType {
  id: string;
  name: string;
  defaultPrice: number;
}

export interface Room {
  id: string;
  roomNo: string;
  floorId: string;
  roomTypeId: string;
  isSmoking: boolean;
  isHandicap: boolean;
  isNonRoom: boolean;
}

export interface GuestReservation {
  roomNo: string;
  roomType: string;
  guestName: string;
  checkIn: string;
  checkOut: string;
  charges: number;
}

export enum ViewMode {
  DASHBOARD = 'DASHBOARD',
  SETTINGS = 'SETTINGS'
}

import React from 'react';

export const ICONS = {
