export const INITIAL_FLOORS = [
  { id: '1', name: '1' },
  { id: '2', name: '2' },
  { id: '3', name: '3' },
  { id: '4', name: '4' },
  { id: '5', name: '5' },
  { id: '6', name: '6' },
];

export const INITIAL_ROOM_TYPES = [
  { id: 'rt1', name: 'DD', defaultPrice: 150 },
  { id: 'rt2', name: 'NK', defaultPrice: 180 },
