export const INITIAL_ROOMS = [
  { id: 'r101', roomNo: '101', floorId: '1', roomTypeId: 'rt1', isSmoking: false, isHandicap: false, isNonRoom: false },
  { id: 'r102', roomNo: '102', floorId: '1', roomTypeId: 'rt2', isSmoking: true, isHandicap: false, isNonRoom: false },
  { id: 'r103', roomNo: 'Elevator-L1', floorId: '1', roomTypeId: 'rt1', isSmoking: false, isHandicap: false, isNonRoom: true },
  { id: 'r201', roomNo: '201', floorId: '2', roomTypeId: 'rt3', isSmoking: false, isHandicap: true, isNonRoom: false },
