import React from 'react';
import { Room, RoomType, GuestReservation } from '../types';
import { ICONS } from '../constants';

interface RoomCardProps {
  room: Room;
  roomType?: RoomType;
  onClick: (room: Room) => void;
}

const RoomCard: React.FC<RoomCardProps> = ({ room, roomType, onClick }) => {
  if (room.isNonRoom) {
    return (
      <div className="bg-slate-200 border border-slate-300 rounded shadow-sm h-24 flex items-center justify-center cursor-not-allowed grayscale opacity-60">
        <div className="text-center">
          <div className="text-slate-500 font-bold text-sm">{room.roomNo}</div>
          <div className="text-slate-400 text-xs uppercase tracking-wider">Storage/Utility</div>
        </div>
      </div>
    );
  }

  return (
    <button
      onClick={() => onClick(room)}
      className="bg-white border border-slate-300 rounded shadow-sm hover:shadow-md hover:border-blue-400 transition-all h-24 p-3 flex flex-col justify-between text-left group"
    >
      <div className="flex justify-between items-start">
        <span className="text-lg font-bold text-slate-800 group-hover:text-blue-600 transition-colors">
          {room.roomNo}
        </span>
        <span className="text-[10px] font-semibold bg-slate-100 text-slate-600 px-1.5 py-0.5 rounded border border-slate-200">
          {roomType?.name || '??'}
        </span>
      </div>

      <div className="flex items-center gap-2 mt-auto">
        {room.isSmoking && (
          <div title="Smoking Allowed">
            <ICONS.Smoking className="text-slate-400" />
          </div>
        )}
        {room.isHandicap && (
          <div title="Handicap Accessible">
            <ICONS.Handicap className="text-slate-400" />
          </div>
        )}
      </div>
    </button>
  );
};

export default RoomCard;

import React, { useState } from 'react';
import { Floor, Room, RoomType } from '../types';
import RoomCard from './RoomCard';
import RoomDetailModal from './RoomDetailModal';

interface DashboardProps {
  floors: Floor[];
  roomTypes: RoomType[];
  rooms: Room[];
  activeFloorId: string | null;
  onSelectFloor: (id: string | null) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  floors, 
  roomTypes, 
  rooms, 
  activeFloorId, 
  onSelectFloor 
}) => {
  const [selectedRoom, setSelectedRoom] = useState<Room | null>(null);

  const filteredRooms = activeFloorId 
    ? rooms.filter(r => r.floorId === activeFloorId)
    : rooms;

  return (
    <div className="flex flex-col h-full">
      {/* Floor Filter Bar */}
      <div className="bg-white border-b border-slate-200 px-6 py-4 flex items-center gap-4 shadow-sm z-10">
        <span className="text-sm font-bold text-slate-500 uppercase tracking-wider mr-2">Floors:</span>
        <div className="flex flex-wrap gap-2">
          <button
            onClick={() => onSelectFloor(null)}
            className={`px-4 py-1.5 rounded text-sm font-semibold border transition-all ${
              activeFloorId === null 
              ? 'bg-blue-600 text-white border-blue-600 shadow-md shadow-blue-100' 
              : 'bg-white text-slate-600 border-slate-200 hover:border-blue-400'
            }`}
          >
            All
          </button>
          {floors.map(floor => (
            <button
              key={floor.id}
              onClick={() => onSelectFloor(floor.id)}
              className={`px-4 py-1.5 rounded text-sm font-semibold border transition-all ${
                activeFloorId === floor.id 
                ? 'bg-blue-600 text-white border-blue-600 shadow-md shadow-blue-100' 
                : 'bg-white text-slate-600 border-slate-200 hover:border-blue-400'
              }`}
            >
              Floor {floor.name}
            </button>
          ))}
        </div>
      </div>

      {/* Main Room Grid */}
      <div className="flex-1 overflow-y-auto p-6">
        {filteredRooms.length === 0 ? (
          <div className="h-full flex flex-col items-center justify-center text-slate-400 space-y-2">
            <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>
            <p className="text-lg">No rooms configured for this floor.</p>
          </div>
        ) : (
          <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 xl:grid-cols-8 gap-4">
            {filteredRooms.map(room => (
              <RoomCard 
                key={room.id} 
                room={room} 
                roomType={roomTypes.find(rt => rt.id === room.roomTypeId)}
                onClick={(r) => !r.isNonRoom && setSelectedRoom(r)}
              />
            ))}
          </div>
        )}
      </div>

      <RoomDetailModal 
        room={selectedRoom}
        roomType={roomTypes.find(rt => rt.id === selectedRoom?.roomTypeId)}
        onClose={() => setSelectedRoom(null)}
      />
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Floor, Room, RoomType } from '../types';

interface RoomSettingsProps {
  floors: Floor[];
  roomTypes: RoomType[];
  onAddFloor: (name: string) => void;
  onAddRoomType: (name: string, price: number) => void;
  onAddRoom: (room: Omit<Room, 'id'>) => void;
}

const RoomSettings: React.FC<RoomSettingsProps> = ({
  floors,
  roomTypes,
  onAddFloor,
  onAddRoomType,
  onAddRoom
}) => {
  // Local form states
  const [floorName, setFloorName] = useState('');
  const [rtName, setRtName] = useState('');
  const [rtPrice, setRtPrice] = useState(0);

  const [newRoomNo, setNewRoomNo] = useState('');
  const [newRoomFloor, setNewRoomFloor] = useState(floors[0]?.id || '');
  const [newRoomType, setNewRoomType] = useState(roomTypes[0]?.id || '');
  const [isSmoking, setIsSmoking] = useState(false);
  const [isHandicap, setIsHandicap] = useState(false);
  const [isNonRoom, setIsNonRoom] = useState(false);

  const handleAddFloor = (e: React.FormEvent) => {
    e.preventDefault();
    if (floorName.trim()) {
      onAddFloor(floorName.trim());
      setFloorName('');
    }
  };

  const handleAddRoomType = (e: React.FormEvent) => {
    e.preventDefault();
    if (rtName.trim() && rtPrice > 0) {
      onAddRoomType(rtName.trim(), rtPrice);
      setRtName('');
      setRtPrice(0);
    }
  };

  const handleAddRoom = (e: React.FormEvent) => {
    e.preventDefault();
    if (newRoomNo.trim()) {
      onAddRoom({
        roomNo: newRoomNo.trim(),
        floorId: newRoomFloor,
        roomTypeId: newRoomType,
        isSmoking: isNonRoom ? false : isSmoking,
        isHandicap: isNonRoom ? false : isHandicap,
        isNonRoom
      });
      setNewRoomNo('');
      setIsSmoking(false);
      setIsHandicap(false);
      setIsNonRoom(false);
    }
  };

  return (
    <div className="p-8 max-w-6xl mx-auto h-full overflow-y-auto space-y-8 pb-20">
      <div className="flex flex-col border-b border-slate-200 pb-4 mb-8">
        <h1 className="text-2xl font-bold text-slate-800 tracking-tight">System Configuration</h1>
        <p className="text-slate-500 text-sm">Manage floors, room types, and inventory definitions.</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {/* A. Floor Setup */}
        <section className="bg-white p-6 rounded-lg border border-slate-200 shadow-sm flex flex-col">
          <h2 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
            <span className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 text-sm font-bold">A</span>
            Floor Setup
          </h2>
          <form onSubmit={handleAddFloor} className="flex gap-2 mb-6">
            <input
              type="text"
              placeholder="Floor No/Name (e.g. 7)"
              value={floorName}
              onChange={(e) => setFloorName(e.target.value)}
              className="flex-1 px-3 py-2 border border-slate-300 rounded text-sm focus:ring-2 focus:ring-blue-500 focus:outline-none"
            />
            <button type="submit" className="bg-slate-800 text-white px-4 py-2 rounded text-sm font-semibold hover:bg-slate-900 transition-all">
              Add
            </button>
          </form>
          <div className="flex-1 border border-slate-100 rounded overflow-hidden">
             <div className="bg-slate-50 px-3 py-2 text-[10px] font-bold text-slate-500 uppercase border-b border-slate-100">Configured Floors</div>
             <div className="p-2 flex flex-wrap gap-2 max-h-32 overflow-y-auto">
               {floors.map(f => (
                 <span key={f.id} className="px-3 py-1 bg-slate-100 text-slate-600 rounded text-xs border border-slate-200">Floor {f.name}</span>
               ))}
             </div>
          </div>
        </section>

        {/* B. Room Type Setup */}
        <section className="bg-white p-6 rounded-lg border border-slate-200 shadow-sm flex flex-col">
          <h2 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
            <span className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 text-sm font-bold">B</span>
            Room Type Setup
          </h2>
          <form onSubmit={handleAddRoomType} className="space-y-3 mb-6">
            <div className="flex gap-2">
              <input
                type="text"
                placeholder="Type Name (e.g. DD, King)"
                value={rtName}
                onChange={(e) => setRtName(e.target.value)}
                className="flex-1 px-3 py-2 border border-slate-300 rounded text-sm focus:ring-2 focus:ring-blue-500 focus:outline-none"
              />
              <input
                type="number"
                placeholder="Price"
                value={rtPrice || ''}
                onChange={(e) => setRtPrice(Number(e.target.value))}
                className="w-24 px-3 py-2 border border-slate-300 rounded text-sm focus:ring-2 focus:ring-blue-500 focus:outline-none"
              />
              <button type="submit" className="bg-slate-800 text-white px-4 py-2 rounded text-sm font-semibold hover:bg-slate-900 transition-all">
                Add
              </button>
            </div>
          </form>
          <div className="flex-1 border border-slate-100 rounded overflow-hidden">
             <div className="bg-slate-50 px-3 py-2 text-[10px] font-bold text-slate-500 uppercase border-b border-slate-100">Room Categories</div>
             <div className="divide-y divide-slate-100 max-h-32 overflow-y-auto">
                {roomTypes.map(rt => (
                  <div key={rt.id} className="px-3 py-1.5 flex justify-between text-xs text-slate-600">
                    <span className="font-medium">{rt.name}</span>
                    <span className="text-slate-400">${rt.defaultPrice}/night</span>
                  </div>
                ))}
             </div>
          </div>
        </section>

        {/* C. Room Creation */}
        <section className="bg-white p-6 rounded-lg border border-slate-200 shadow-sm col-span-1 md:col-span-2">
          <h2 className="text-lg font-semibold text-slate-800 mb-6 flex items-center gap-2">
            <span className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 text-sm font-bold">C</span>
            Room Inventory Creation
          </h2>
          <form onSubmit={handleAddRoom} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="space-y-1.5">
                <label className="text-xs font-bold text-slate-500 uppercase">Room Number</label>
                <input
                  type="text"
                  required
                  placeholder="e.g. 104"
                  value={newRoomNo}
                  onChange={(e) => setNewRoomNo(e.target.value)}
                  className="w-full px-3 py-2 border border-slate-300 rounded text-sm focus:ring-2 focus:ring-blue-500 focus:outline-none"
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-xs font-bold text-slate-500 uppercase">Floor</label>
                <select
                  value={newRoomFloor}
                  onChange={(e) => setNewRoomFloor(e.target.value)}
                  className="w-full px-3 py-2 border border-slate-300 rounded text-sm focus:ring-2 focus:ring-blue-500 focus:outline-none bg-white"
                >
                  {floors.map(f => <option key={f.id} value={f.id}>Floor {f.name}</option>)}
                </select>
              </div>
              <div className="space-y-1.5">
                <label className="text-xs font-bold text-slate-500 uppercase">Room Type</label>
                <select
                  value={newRoomType}
                  onChange={(e) => setNewRoomType(e.target.value)}
                  className="w-full px-3 py-2 border border-slate-300 rounded text-sm focus:ring-2 focus:ring-blue-500 focus:outline-none bg-white"
                >
                  {roomTypes.map(rt => <option key={rt.id} value={rt.id}>{rt.name}</option>)}
                </select>
              </div>
            </div>

            <div className="flex flex-wrap gap-6 bg-slate-50 p-4 rounded border border-slate-100">
               <label className="flex items-center gap-2 cursor-pointer group">
                 <input 
                  type="checkbox" 
                  checked={isSmoking} 
                  disabled={isNonRoom}
                  onChange={(e) => setIsSmoking(e.target.checked)}
                  className="w-4 h-4 rounded text-blue-600 focus:ring-blue-500 border-slate-300 cursor-pointer" 
                 />
                 <span className={`text-sm ${isNonRoom ? 'text-slate-300' : 'text-slate-600 font-medium'}`}>Smoking Allowed</span>
               </label>
               <label className="flex items-center gap-2 cursor-pointer group">
                 <input 
                  type="checkbox" 
                  checked={isHandicap} 
                  disabled={isNonRoom}
                  onChange={(e) => setIsHandicap(e.target.checked)}
                  className="w-4 h-4 rounded text-blue-600 focus:ring-blue-500 border-slate-300 cursor-pointer" 
                 />
                 <span className={`text-sm ${isNonRoom ? 'text-slate-300' : 'text-slate-600 font-medium'}`}>Handicap Accessible</span>
               </label>
               <div className="h-6 w-px bg-slate-200 mx-2 hidden sm:block"></div>
               <label className="flex items-center gap-2 cursor-pointer group">
                 <input 
                  type="checkbox" 
                  checked={isNonRoom} 
                  onChange={(e) => setIsNonRoom(e.target.checked)}
                  className="w-4 h-4 rounded text-red-500 focus:ring-red-500 border-slate-300 cursor-pointer" 
                 />
                 <span className="text-sm text-red-600 font-bold">Non-Room / Service Area</span>
               </label>
            </div>

            <div className="flex justify-end pt-2">
              <button 
                type="submit" 
                className="bg-blue-600 text-white px-8 py-2.5 rounded shadow-lg shadow-blue-100 hover:bg-blue-700 font-bold transition-all text-sm uppercase tracking-wider"
              >
                Create Room
              </button>
            </div>
          </form>
        </section>
      </div>
    </div>
  );
};

export default RoomSettings;

import React, { useState, useCallback } from 'react';
import { Floor, Room, RoomType, ViewMode } from './types';
import { INITIAL_FLOORS, INITIAL_ROOM_TYPES, INITIAL_ROOMS, ICONS } from './constants';
import Dashboard from './components/Dashboard';
import RoomSettings from './components/RoomSettings';

const App: React.FC = () => {
  const [viewMode, setViewMode] = useState<ViewMode>(ViewMode.DASHBOARD);
  const [floors, setFloors] = useState<Floor[]>(INITIAL_FLOORS);
  const [roomTypes, setRoomTypes] = useState<RoomType[]>(INITIAL_ROOM_TYPES);
  const [rooms, setRooms] = useState<Room[]>(INITIAL_ROOMS);
  const [activeFloorId, setActiveFloorId] = useState<string | null>(null);
  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]);

  // Handlers
  const addFloor = (name: string) => {
    const newFloor: Floor = { id: Date.now().toString(), name };
    setFloors(prev => [...prev, newFloor]);
  };

  const addRoomType = (name: string, price: number) => {
    const newRT: RoomType = { id: Date.now().toString(), name, defaultPrice: price };
    setRoomTypes(prev => [...prev, newRT]);
  };

  const addRoom = (roomData: Omit<Room, 'id'>) => {
    const newRoom: Room = { ...roomData, id: Date.now().toString() };
    setRooms(prev => [...prev, newRoom]);
    setViewMode(ViewMode.DASHBOARD); // Return to dashboard to see new room
  };

  return (
    <div className="flex h-screen overflow-hidden text-slate-800">
      {/* Sidebar */}
      <aside className="w-64 bg-slate-900 text-slate-300 flex flex-col shrink-0 border-r border-slate-800">
        <div className="p-6 border-b border-slate-800">
          <div className="flex items-center gap-3">
            <div className="w-8 h-8 bg-blue-600 rounded flex items-center justify-center font-bold text-white shadow-lg shadow-blue-900/50">H</div>
            <span className="font-bold text-white tracking-tight">Grand PMS</span>
          </div>
          <div className="mt-6">
            <label className="text-[10px] font-bold text-slate-500 uppercase block mb-2">Business Date</label>
            <input 
              type="date" 
              value={selectedDate}
              onChange={(e) => setSelectedDate(e.target.value)}
              className="w-full bg-slate-800 border border-slate-700 rounded px-3 py-1.5 text-xs text-white focus:ring-1 focus:ring-blue-500 outline-none" 
            />
          </div>
        </div>

        <nav className="flex-1 py-4">
          <button 
            onClick={() => setViewMode(ViewMode.DASHBOARD)}
            className={`w-full flex items-center gap-3 px-6 py-3 text-sm font-medium transition-colors border-l-4 ${
              viewMode === ViewMode.DASHBOARD 
              ? 'bg-blue-600/10 text-blue-400 border-blue-600' 
              : 'text-slate-400 border-transparent hover:bg-slate-800'
            }`}
          >
            <ICONS.Grid />
            Dashboard
          </button>
          <button 
            onClick={() => setViewMode(ViewMode.SETTINGS)}
            className={`w-full flex items-center gap-3 px-6 py-3 text-sm font-medium transition-colors border-l-4 ${
              viewMode === ViewMode.SETTINGS 
              ? 'bg-blue-600/10 text-blue-400 border-blue-600' 
              : 'text-slate-400 border-transparent hover:bg-slate-800'
            }`}
          >
            <ICONS.Settings />
            Room Settings (Admin)
          </button>
        </nav>

        <div className="p-6 border-t border-slate-800 text-[10px] text-slate-500 uppercase tracking-widest font-bold text-center">
          V 1.0.4 Enterprise
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 flex flex-col min-w-0">
        {/* Top Horizontal Bar */}
        <header className="h-14 bg-white border-b border-slate-200 flex items-center justify-between px-6 shrink-0 z-20">
          <div className="flex items-center gap-8">
            <div className="flex gap-4 text-xs font-semibold text-slate-500">
              <button className="hover:text-blue-600 transition-colors cursor-pointer">File</button>
              <button className="hover:text-blue-600 transition-colors cursor-pointer">Edit</button>
              <button className="text-red-500 hover:text-red-700 transition-colors cursor-pointer">Exit</button>
            </div>
