const RoomInventory: React.FC<{ floors: Floor[], roomTypes: RoomType[], onAdd: (r: Omit<Room, 'id'>) => void, onBack: () => void }> = ({ floors, roomTypes, onAdd, onBack }) => {
  const [no, setNo] = useState('');
  const [floor, setFloor] = useState(floors[0]?.id || '');
  const [type, setType] = useState(roomTypes[0]?.id || '');
  const [smoking, setSmoking] = useState(false);
  const [handicap, setHandicap] = useState(false);
  const [nonRoom, setNonRoom] = useState(false);

  return (
    <div className="p-8 max-w-3xl mx-auto">
      <button onClick={onBack} className="text-sm text-blue-600 font-semibold mb-4 flex items-center gap-1 hover:underline">
        ← Back to Settings Menu
      </button>
      <div className="bg-white p-8 rounded-lg border border-slate-200 shadow-sm">
        <h2 className="text-xl font-bold text-slate-800 mb-8">Room Creation</h2>
        <form onSubmit={(e) => { e.preventDefault(); onAdd({ roomNo: no, floorId: floor, roomTypeId: type, isSmoking: nonRoom ? false : smoking, isHandicap: nonRoom ? false : handicap, isNonRoom: nonRoom }); }} className="space-y-6">
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
            <div className="space-y-1.5">
              <label className="text-xs font-bold text-slate-500 uppercase">Room Number</label>
              <input required value={no} onChange={e => setNo(e.target.value)} className="w-full px-3 py-2 border border-slate-300 rounded text-sm focus:ring-2 focus:ring-blue-500 outline-none" />
            </div>
            <div className="space-y-1.5">
              <label className="text-xs font-bold text-slate-500 uppercase">Floor</label>
              <select value={floor} onChange={e => setFloor(e.target.value)} className="w-full px-3 py-2 border border-slate-300 rounded text-sm bg-white outline-none">
                {floors.map(f => <option key={f.id} value={f.id}>Floor {f.name}</option>)}
              </select>
            </div>
            <div className="space-y-1.5">
              <label className="text-xs font-bold text-slate-500 uppercase">Room Type</label>
              <select value={type} onChange={e => setType(e.target.value)} className="w-full px-3 py-2 border border-slate-300 rounded text-sm bg-white outline-none">
                {roomTypes.map(rt => <option key={rt.id} value={rt.id}>{rt.name}</option>)}
              </select>
            </div>
          </div>

          <div className="flex flex-col gap-4 bg-slate-50 p-6 rounded border border-slate-100">
            <label className="flex items-center gap-3 cursor-pointer">
              <input type="checkbox" checked={smoking} disabled={nonRoom} onChange={e => setSmoking(e.target.checked)} className="w-4 h-4 text-blue-600 rounded" />
              <span className={`text-sm ${nonRoom ? 'text-slate-300' : 'text-slate-600 font-medium'}`}>Smoking Allowed</span>
            </label>
            <label className="flex items-center gap-3 cursor-pointer">
              <input type="checkbox" checked={handicap} disabled={nonRoom} onChange={e => setHandicap(e.target.checked)} className="w-4 h-4 text-blue-600 rounded" />
              <span className={`text-sm ${nonRoom ? 'text-slate-300' : 'text-slate-600 font-medium'}`}>Handicap Accessible</span>
            </label>
            <hr className="border-slate-200 my-2" />
            <label className="flex items-center gap-3 cursor-pointer">
              <input type="checkbox" checked={nonRoom} onChange={e => setNonRoom(e.target.checked)} className="w-4 h-4 text-red-500 border-red-300 rounded" />
              <span className="text-sm text-red-700 font-bold">Non-Room (Storage/Elevator/etc.)</span>
            </label>
          </div>

          <div className="flex justify-end">
            <button type="submit" className="bg-blue-600 text-white px-8 py-3 rounded font-bold shadow-lg shadow-blue-100 hover:bg-blue-700 transition-all text-sm uppercase tracking-wider">
              Create Room
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

const RoomSettings: React.FC<RoomSettingsProps> = (props) => {
  const { viewMode, setViewMode } = props;

  switch (viewMode) {
    case ViewMode.SETTINGS_FLOOR:
      return <FloorSetup floors={props.floors} onAddFloor={props.onAddFloor} onBack={() => setViewMode(ViewMode.SETTINGS_MENU)} />;
    case ViewMode.SETTINGS_ROOM_TYPE:
      return <RoomTypeSetup roomTypes={props.roomTypes} onAdd={props.onAddRoomType} onBack={() => setViewMode(ViewMode.SETTINGS_MENU)} />;
    case ViewMode.SETTINGS_ROOM:
      return <RoomInventory floors={props.floors} roomTypes={props.roomTypes} onAdd={props.onAddRoom} onBack={() => setViewMode(ViewMode.SETTINGS_MENU)} />;
    default:
      return <SettingsMenu setViewMode={setViewMode} />;
  }
};

export default RoomSettings;

