    <div className="p-8 max-w-2xl mx-auto">
      <div className="bg-white p-8 rounded-lg border border-slate-200 shadow-sm">
        <h2 className="text-xl font-bold text-slate-800 mb-6 border-b border-slate-100 pb-4">Floor Configuration</h2>
        <form onSubmit={(e) => { e.preventDefault(); if(name) { onAddFloor(name); setName(''); }}} className="flex gap-2 mb-8">
          <input
            type="text"
            placeholder="Floor Number or Name (e.g. 7)"
            value={name}
            onChange={(e) => setName(e.target.value)}
            className="flex-1 px-4 py-2 border border-slate-300 rounded text-sm focus:ring-2 focus:ring-blue-500 outline-none"
          />
