        <form onSubmit={(e) => { e.preventDefault(); if(name) { onAddFloor(name); setName(''); }}} className="flex gap-3 mb-10">
          <div className="flex-1 relative">
            <input
              type="text"
              placeholder="Enter Floor Number or Designation"
              value={name}
              onChange={(e) => setName(e.target.value)}
