          <p className="text-sm text-slate-500 mt-1">Manage room classification codes and baseline nightly rates.</p>
        </div>

        <form onSubmit={(e) => { e.preventDefault(); if(name && price > 0) { onAdd(name, price); setName(''); setPrice(0); setSelectedTypeId(null); }}} className="space-y-5 mb-10 bg-slate-50 p-6 rounded-xl border border-slate-100">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
