                roomTypes.map(rt => (
                <button 
                  key={rt.id} 
                  onClick={() => handleEditClick(rt)}
                  className={`px-5 py-4 flex justify-between items-center rounded-xl border transition-all text-left group ${
                    selectedTypeId === rt.id 
                    ? 'bg-blue-600 border-blue-600 text-white shadow-lg shadow-blue-200 scale-[1.02]' 
                    : 'bg-white border-slate-200 hover:border-blue-400 hover:shadow-md'
