                        <span className={`text-xs font-bold uppercase tracking-widest mb-0.5 ${selectedTypeId === rt.id ? 'text-blue-100' : 'text-slate-400'}`}>Code</span>
                        <span className={`text-lg font-black ${selectedTypeId === rt.id ? 'text-white' : 'text-slate-800'}`}>{rt.name}</span>
                    </div>
                    <div className="text-right">
                        <span className={`block text-[10px] font-bold uppercase tracking-widest mb-0.5 ${selectedTypeId === rt.id ? 'text-blue-100' : 'text-slate-400'}`}>Rate</span>
                        <span className={`text-xl font-black ${selectedTypeId === rt.id ? 'text-white' : 'text-blue-600'}`}>${rt.defaultPrice}</span>
                    </div>
                </button>
                ))
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

