        <form onSubmit={(e) => { e.preventDefault(); onAdd({ roomNo: no, floorId: floor, roomTypeId: type, isSmoking: nonRoom ? false : smoking, isHandicap: nonRoom ? false : handicap, isNonRoom: nonRoom }); }} className="space-y-8">
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-8">
            <div className="space-y-2">
              <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest px-1">Room No.</label>
