            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest px-1">Floor Level</label>
              <select value={floor} onChange={e => setFloor(e.target.value)} className="w-full px-4 py-3 border border-slate-300 rounded-lg text-sm bg-white outline-none focus:ring-2 focus:ring-blue-500 transition-all shadow-sm">
                {floors.map(f => <option key={f.id} value={f.id}>Floor {f.name}</option>)}
