            <div className="space-y-2">
              <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest px-1">Unit Category</label>
              <select value={type} onChange={e => setType(e.target.value)} className="w-full px-4 py-3 border border-slate-300 rounded-lg text-sm bg-white outline-none focus:ring-2 focus:ring-blue-500 transition-all shadow-sm">
                {roomTypes.map(rt => <option key={rt.id} value={rt.id}>{rt.name}</option>)}
