          <div className="space-y-3">
             <label className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em] block mb-4">Unit Attributes</label>
             <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <label className={`flex items-center gap-4 px-6 py-4 rounded-xl border cursor-pointer select-none transition-all ${smoking && !nonRoom ? 'bg-blue-50 border-blue-200' : 'bg-white border-slate-200 hover:bg-slate-50'}`}>
                  <input type="checkbox" checked={smoking} disabled={nonRoom} onChange={e => setSmoking(e.target.checked)} className="w-5 h-5 text-blue-600 rounded focus:ring-blue-500 transition-all" />
                  <div className="flex flex-col">
                    <span className={`text-sm font-bold ${nonRoom ? 'text-slate-300' : 'text-slate-700'}`}>Smoking Permitted</span>
                    <span className="text-[10px] text-slate-400 uppercase tracking-tight">Designated smoking zone</span>
                  </div>
                </label>
                <label className={`flex items-center gap-4 px-6 py-4 rounded-xl border cursor-pointer select-none transition-all ${handicap && !nonRoom ? 'bg-blue-50 border-blue-200' : 'bg-white border-slate-200 hover:bg-slate-50'}`}>
                  <input type="checkbox" checked={handicap} disabled={nonRoom} onChange={e => setHandicap(e.target.checked)} className="w-5 h-5 text-blue-600 rounded focus:ring-blue-500 transition-all" />
                  <div className="flex flex-col">
                    <span className={`text-sm font-bold ${nonRoom ? 'text-slate-300' : 'text-slate-700'}`}>ADA Accessible</span>
                    <span className="text-[10px] text-slate-400 uppercase tracking-tight">Handicap facilities equipped</span>
                  </div>
                </label>
             </div>

             <div className="mt-6">
                <label className={`flex items-center gap-4 px-6 py-5 rounded-xl border cursor-pointer select-none transition-all ${nonRoom ? 'bg-red-50 border-red-200 shadow-lg shadow-red-50' : 'bg-slate-50 border-slate-200 hover:border-red-200'}`}>
