          <div className="flex justify-end pt-6">
            <button type="submit" className="bg-slate-900 text-white px-12 py-4 rounded-xl font-black shadow-xl shadow-slate-200 hover:bg-black transition-all text-sm uppercase tracking-[0.2em]">
              Commit to Inventory
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

const RoomSettings: React.FC<RoomSettingsProps> = (props) => {
  const { viewMode } = props;

