import React, { useState } from 'react';
import { Floor, Room, RoomType, ViewMode } from './types';
import { INITIAL_FLOORS, INITIAL_ROOM_TYPES, INITIAL_ROOMS, ICONS } from './constants';
import Dashboard from './components/Dashboard';
import RoomSettings from './components/RoomSettings';

const App: React.FC = () => {
  const [viewMode, setViewMode] = useState<ViewMode>(ViewMode.DASHBOARD);
  const [floors, setFloors] = useState<Floor[]>(INITIAL_FLOORS);
  const [roomTypes, setRoomTypes] = useState<RoomType[]>(INITIAL_ROOM_TYPES);
  const [rooms, setRooms] = useState<Room[]>(INITIAL_ROOMS);
  const [activeFloorId, setActiveFloorId] = useState<string | null>(null);
  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]);

  const addFloor = (name: string) => {
    const newFloor: Floor = { id: Date.now().toString(), name };
    setFloors(prev => [...prev, newFloor]);
  };

  const addRoomType = (name: string, price: number) => {
    const newRT: RoomType = { id: Date.now().toString(), name, defaultPrice: price };
    setRoomTypes(prev => [...prev, newRT]);
  };

  const addRoom = (roomData: Omit<Room, 'id'>) => {
    const newRoom: Room = { ...roomData, id: Date.now().toString() };
    setRooms(prev => [...prev, newRoom]);
    setViewMode(ViewMode.DASHBOARD);
  };

  const isAdminActive = viewMode.startsWith('SETTINGS_');

  const NavButton = ({ mode, label, icon: Icon, isSubItem = false }: { mode: ViewMode, label: string, icon: any, isSubItem?: boolean }) => {
    const isActive = viewMode === mode;
    return (
      <button 
        onClick={() => setViewMode(mode)}
        className={`w-full flex items-center gap-3 transition-all border-l-4 ${
          isSubItem ? 'pl-10 pr-6 py-2.5 text-xs' : 'px-6 py-3.5 text-sm'
        } font-semibold ${
          isActive 
          ? 'bg-blue-600/15 text-blue-400 border-blue-600 shadow-[inset_0_0_20px_rgba(37,99,235,0.05)]' 
          : 'text-slate-400 border-transparent hover:bg-slate-800 hover:text-slate-200'
        }`}
      >
        <Icon className={`${isActive ? 'text-blue-400' : 'text-slate-500'} ${isSubItem ? 'w-4 h-4' : 'w-5 h-5'}`} />
        {label}
      </button>
    );
  };

  return (
    <div className="flex h-screen overflow-hidden text-slate-800">
      {/* Sidebar */}
      <aside className="w-64 bg-slate-900 text-slate-300 flex flex-col shrink-0 border-r border-slate-800 shadow-2xl z-30">
        <div className="p-6 border-b border-slate-800">
          <div className="flex items-center gap-3">
            <div className="w-8 h-8 bg-blue-600 rounded flex items-center justify-center font-bold text-white shadow-lg shadow-blue-900/50">H</div>
            <span className="font-bold text-white tracking-tight text-lg">Grand PMS</span>
          </div>
          <div className="mt-6">
            <label className="text-[10px] font-bold text-slate-500 uppercase block mb-2 tracking-widest">Business Date</label>
            <div className="relative">
              <input 
                type="date" 
                value={selectedDate}
                onChange={(e) => setSelectedDate(e.target.value)}
                className="w-full bg-slate-800 border border-slate-700 rounded-md px-3 py-2 text-xs text-white outline-none focus:ring-1 focus:ring-blue-500 transition-all appearance-none" 
              />
            </div>
          </div>
        </div>

        <nav className="flex-1 py-6 overflow-y-auto">
          {/* Main Operational Dashboard */}
          <div className="mb-4">
            <NavButton mode={ViewMode.DASHBOARD} label="Room Dashboard" icon={ICONS.Grid} />
          </div>

          {/* Admin Entry Point */}
          <div className="border-t border-slate-800/50 pt-4">
            <button 
                onClick={() => setViewMode(ViewMode.SETTINGS_MENU)}
                className={`w-full flex items-center gap-3 px-6 py-3.5 text-sm font-semibold transition-all border-l-4 ${
                    isAdminActive 
                    ? 'text-blue-400 border-blue-600' 
                    : 'text-slate-400 border-transparent hover:bg-slate-800 hover:text-slate-200'
                }`}
            >
                <ICONS.Settings className={isAdminActive ? 'text-blue-400' : 'text-slate-500'} />
                Room Settings (Admin)
            </button>

            {/* Sub-options only shown when Admin is active */}
            {isAdminActive && (
              <div className="mt-2 flex flex-col space-y-1 bg-slate-950/20 py-2">
                <NavButton mode={ViewMode.SETTINGS_FLOOR} label="Floor Setup" icon={ICONS.Floor} isSubItem />
                <NavButton mode={ViewMode.SETTINGS_ROOM_TYPE} label="Room Type Setup" icon={ICONS.RoomType} isSubItem />
                <NavButton mode={ViewMode.SETTINGS_ROOM} label="Room Inventory" icon={ICONS.Inventory} isSubItem />
              </div>
            )}
          </div>
        </nav>

        <div className="p-6 border-t border-slate-800 bg-slate-950/20 text-[10px] text-slate-600 uppercase tracking-widest font-bold text-center">
          V 1.0.4 Enterprise Elite
        </div>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 bg-slate-50">
        <header className="h-14 bg-white border-b border-slate-200 flex items-center justify-between px-8 shrink-0 z-20 shadow-sm">
          <div className="flex items-center gap-10">
            <div className="flex gap-6 text-xs font-bold text-slate-400 uppercase tracking-wider">
              <button className="hover:text-blue-600 transition-colors">File</button>
              <button className="hover:text-blue-600 transition-colors">Edit</button>
              <button className="text-red-400/80 hover:text-red-600 transition-colors">Exit System</button>
            </div>
            <div className="h-4 w-px bg-slate-200"></div>
            <div className="flex items-center gap-2">
               <span className="text-[10px] font-bold text-slate-400 uppercase tracking-wider">Access Level:</span>
               <span className="text-xs font-bold text-slate-700 bg-slate-100 px-2 py-0.5 rounded">Super Admin</span>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <div className="flex items-center gap-2 text-slate-500">
               <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
               <span className="text-xs font-bold tracking-tight">System Online</span>
            </div>
          </div>
        </header>

        <div className="flex-1 min-h-0 overflow-hidden">
          {viewMode === ViewMode.DASHBOARD ? (
            <Dashboard 
              floors={floors}
              roomTypes={roomTypes}
              rooms={rooms}
              activeFloorId={activeFloorId}
              onSelectFloor={setActiveFloorId}
            />
          ) : (
            <div className="h-full overflow-y-auto">
              <RoomSettings 
                viewMode={viewMode}
                setViewMode={setViewMode}
                floors={floors}
                roomTypes={roomTypes}
                onAddFloor={addFloor}
                onAddRoomType={addRoomType}
                onAddRoom={addRoom}
              />
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

