interface RoomSettingsProps {
  viewMode: ViewMode;
  setViewMode: (mode: ViewMode) => void;
  floors: Floor[];
  roomTypes: RoomType[];
  onAddFloor: (name: string) => void;
  onAddRoomType: (name: string, price: number) => void;
  onAddRoom: (room: Omit<Room, 'id'>) => void;
}

const FloorSetup: React.FC<{ floors: Floor[], onAddFloor: (n: string) => void }> = ({ floors, onAddFloor }) => {
  const [name, setName] = useState('');
  return (
    <div className="p-10 max-w-3xl mx-auto">
      <div className="bg-white p-10 rounded-xl border border-slate-200 shadow-xl shadow-slate-200/50">
        <div className="mb-8 border-b border-slate-100 pb-6">
          <h2 className="text-2xl font-extrabold text-slate-800">Floor Architecture</h2>
          <p className="text-sm text-slate-500 mt-1">Define property levels and spatial hierarchy.</p>
        </div>

        <form onSubmit={(e) => { e.preventDefault(); if(name) { onAddFloor(name); setName(''); }}} className="flex gap-3 mb-10">
          <input
            type="text"
            placeholder="Floor Designation (e.g. Lobby, Level 1)"
            value={name}
            onChange={(e) => setName(e.target.value)}
            className="flex-1 px-4 py-3 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none transition-all"
          />
          <button type="submit" className="bg-slate-900 text-white px-8 py-3 rounded-lg text-sm font-bold hover:bg-black transition-all shadow-md uppercase tracking-wider">
            Add
          </button>
        </form>

        <div className="border border-slate-100 rounded-xl bg-slate-50/30 overflow-hidden">
          <div className="bg-white px-5 py-3 text-[10px] font-extrabold text-slate-400 uppercase border-b border-slate-100 tracking-widest">Configured Floors</div>
          <div className="grid grid-cols-2 sm:grid-cols-3 gap-3 p-5 max-h-[400px] overflow-y-auto">
            {floors.map(f => (
              <div key={f.id} className="bg-white p-4 rounded-lg border border-slate-200 flex flex-col items-center justify-center gap-1 shadow-sm">
                <span className="text-[10px] font-bold text-slate-400 uppercase">Floor</span>
                <span className="text-xl font-extrabold text-slate-800">{f.name}</span>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

const RoomTypeSetup: React.FC<{ roomTypes: RoomType[], onAdd: (n: string, p: number) => void }> = ({ roomTypes, onAdd }) => {
  const [name, setName] = useState('');
  const [price, setPrice] = useState(0);
  const [selectedTypeId, setSelectedTypeId] = useState<string | null>(null);

  const handleEditClick = (rt: RoomType) => {
    setSelectedTypeId(rt.id);
    setName(rt.name);
    setPrice(rt.defaultPrice);
  };

  return (
    <div className="p-10 max-w-4xl mx-auto">
      <div className="bg-white p-10 rounded-xl border border-slate-200 shadow-xl shadow-slate-200/50">
        <div className="mb-8 border-b border-slate-100 pb-6 text-center sm:text-left">
          <h2 className="text-2xl font-extrabold text-slate-800">Room Categories & Rates</h2>
          <p className="text-sm text-slate-500 mt-1">Configure baseline revenue classes for room inventory.</p>
        </div>

        <form onSubmit={(e) => { e.preventDefault(); if(name && price > 0) { onAdd(name, price); setName(''); setPrice(0); setSelectedTypeId(null); }}} className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-10 bg-slate-50 p-6 rounded-xl border border-slate-100">
          <div className="sm:col-span-1">
            <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest block mb-1">Type Code</label>
            <input
              type="text"
              placeholder="e.g. DLX, STE"
              value={name}
              onChange={(e) => setName(e.target.value)}
              className="w-full px-4 py-3 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none bg-white transition-all"
            />
          </div>
          <div className="sm:col-span-1">
            <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest block mb-1">Nightly Rate ($)</label>
            <input
              type="number"
              placeholder="Rate"
              value={price || ''}
              onChange={(e) => setPrice(Number(e.target.value))}
              className="w-full px-4 py-3 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none bg-white transition-all"
            />
          </div>
          <div className="sm:col-span-1 flex items-end">
            <button type="submit" className="w-full bg-blue-600 text-white py-3 rounded-lg text-sm font-bold hover:bg-blue-700 transition-all shadow-md uppercase tracking-wider">
              {selectedTypeId ? 'Update' : 'Add Type'}
            </button>
          </div>
        </form>

        <div>
          <h4 className="text-[10px] font-extrabold text-slate-400 uppercase tracking-widest mb-4">Click to Select Category</h4>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 max-h-[400px] overflow-y-auto p-1">
            {roomTypes.map(rt => (
              <button 
                key={rt.id} 
                onClick={() => handleEditClick(rt)}
                className={`p-5 flex justify-between items-center rounded-xl border transition-all text-left shadow-sm ${
                  selectedTypeId === rt.id 
                  ? 'bg-blue-600 border-blue-600 text-white ring-4 ring-blue-500/10 scale-[1.01]' 
                  : 'bg-white border-slate-200 hover:border-blue-400 hover:shadow-md'
                }`}
              >
                <div>
                  <div className={`text-[10px] font-bold uppercase mb-0.5 ${selectedTypeId === rt.id ? 'text-blue-100' : 'text-slate-400'}`}>Category Code</div>
                  <div className="text-lg font-black">{rt.name}</div>
                </div>
                <div className="text-right">
                  <div className={`text-[10px] font-bold uppercase mb-0.5 ${selectedTypeId === rt.id ? 'text-blue-100' : 'text-slate-400'}`}>Standard Rate</div>
                  <div className={`text-xl font-black ${selectedTypeId === rt.id ? 'text-white' : 'text-blue-600'}`}>${rt.defaultPrice}</div>
                </div>
              </button>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

const RoomInventory: React.FC<{ floors: Floor[], roomTypes: RoomType[], onAdd: (r: Omit<Room, 'id'>) => void }> = ({ floors, roomTypes, onAdd }) => {
  const [no, setNo] = useState('');
  const [floor, setFloor] = useState(floors[0]?.id || '');
  const [type, setType] = useState(roomTypes[0]?.id || '');
  const [smoking, setSmoking] = useState(false);
  const [handicap, setHandicap] = useState(false);
  const [nonRoom, setNonRoom] = useState(false);

  return (
    <div className="p-10 max-w-4xl mx-auto">
      <div className="bg-white p-10 rounded-xl border border-slate-200 shadow-xl shadow-slate-200/50">
        <div className="mb-8 border-b border-slate-100 pb-6">
          <h2 className="text-2xl font-extrabold text-slate-800">Unit Registration</h2>
          <p className="text-sm text-slate-500 mt-1">Add specific physical rooms to the active property inventory.</p>
        </div>

        <form onSubmit={(e) => { e.preventDefault(); onAdd({ roomNo: no, floorId: floor, roomTypeId: type, isSmoking: nonRoom ? false : smoking, isHandicap: nonRoom ? false : handicap, isNonRoom: nonRoom }); }} className="space-y-6">
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
            <div>
              <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest block mb-1">Room No.</label>
              <input required value={no} onChange={e => setNo(e.target.value)} placeholder="e.g. 101" className="w-full px-4 py-3 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none" />
            </div>
            <div>
              <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest block mb-1">Floor</label>
              <select value={floor} onChange={e => setFloor(e.target.value)} className="w-full px-4 py-3 border border-slate-300 rounded-lg text-sm bg-white outline-none focus:ring-2 focus:ring-blue-500">
                {floors.map(f => <option key={f.id} value={f.id}>Level {f.name}</option>)}
              </select>
            </div>
            <div>
              <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest block mb-1">Type</label>
              <select value={type} onChange={e => setType(e.target.value)} className="w-full px-4 py-3 border border-slate-300 rounded-lg text-sm bg-white outline-none focus:ring-2 focus:ring-blue-500">
                {roomTypes.map(rt => <option key={rt.id} value={rt.id}>{rt.name}</option>)}
              </select>
            </div>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <label className={`flex items-center gap-3 p-4 rounded-xl border cursor-pointer transition-all ${smoking && !nonRoom ? 'bg-blue-50 border-blue-200' : 'bg-white border-slate-200 hover:bg-slate-50'}`}>
              <input type="checkbox" checked={smoking} disabled={nonRoom} onChange={e => setSmoking(e.target.checked)} className="w-5 h-5 text-blue-600 rounded" />
              <span className={`text-sm font-bold ${nonRoom ? 'text-slate-300' : 'text-slate-700'}`}>Smoking Allowed</span>
            </label>
            <label className={`flex items-center gap-3 p-4 rounded-xl border cursor-pointer transition-all ${handicap && !nonRoom ? 'bg-blue-50 border-blue-200' : 'bg-white border-slate-200 hover:bg-slate-50'}`}>
              <input type="checkbox" checked={handicap} disabled={nonRoom} onChange={e => setHandicap(e.target.checked)} className="w-5 h-5 text-blue-600 rounded" />
              <span className={`text-sm font-bold ${nonRoom ? 'text-slate-300' : 'text-slate-700'}`}>ADA Accessible</span>
            </label>
          </div>

          <label className={`flex items-center gap-3 p-5 rounded-xl border cursor-pointer transition-all ${nonRoom ? 'bg-red-50 border-red-200 shadow-md shadow-red-50' : 'bg-slate-50 border-slate-200 hover:border-red-200'}`}>
            <input type="checkbox" checked={nonRoom} onChange={e => setNonRoom(e.target.checked)} className="w-5 h-5 text-red-600 rounded border-red-300" />
            <span className={`text-sm font-black ${nonRoom ? 'text-red-700' : 'text-slate-500'}`}>NON-ROOM SERVICE ENTITY</span>
          </label>

          <div className="flex justify-end pt-4">
            <button type="submit" className="bg-slate-900 text-white px-12 py-4 rounded-xl font-black shadow-lg hover:bg-black transition-all text-sm uppercase tracking-widest">
              Add to Inventory
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

const AdminMenu: React.FC<{ setViewMode: (mode: ViewMode) => void }> = ({ setViewMode }) => {
  const options = [
    { mode: ViewMode.SETTINGS_FLOOR, title: 'Floor Architecture', icon: ICONS.Floor, desc: 'Define building levels' },
    { mode: ViewMode.SETTINGS_ROOM_TYPE, title: 'Category Pricing', icon: ICONS.RoomType, desc: 'Manage room classes and rates' },
    { mode: ViewMode.SETTINGS_ROOM, title: 'Inventory Creation', icon: ICONS.Inventory, desc: 'Register physical room units' },
  ];

  return (
    <div className="p-10 max-w-5xl mx-auto h-full flex flex-col items-center justify-center">
      <div className="mb-12 text-center">
         <h1 className="text-3xl font-black text-slate-800 tracking-tight">System Administration</h1>
         <p className="text-slate-500 mt-2">Select a configuration module below to manage your property data.</p>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-3 gap-8 w-full">
        {options.map((opt) => (
          <button 
            key={opt.mode}
            onClick={() => setViewMode(opt.mode)}
            className="bg-white p-10 rounded-2xl border border-slate-200 shadow-xl shadow-slate-200/50 hover:border-blue-500 hover:shadow-blue-200 transition-all text-center group flex flex-col items-center"
          >
            <div className="w-16 h-16 bg-slate-100 rounded-2xl flex items-center justify-center text-slate-500 mb-6 group-hover:bg-blue-50 group-hover:text-blue-600 transition-colors">
              <opt.icon className="w-8 h-8" />
            </div>
            <h3 className="text-xl font-bold text-slate-800 mb-2">{opt.title}</h3>
            <p className="text-sm text-slate-500">{opt.desc}</p>
          </button>
        ))}
      </div>
    </div>
  );
};

const RoomSettings: React.FC<RoomSettingsProps> = (props) => {
  const { viewMode, setViewMode } = props;

  switch (viewMode) {
    case ViewMode.SETTINGS_FLOOR:
      return <FloorSetup floors={props.floors} onAddFloor={props.onAddFloor} />;
    case ViewMode.SETTINGS_ROOM_TYPE:
      return <RoomTypeSetup roomTypes={props.roomTypes} onAdd={props.onAddRoomType} />;
    case ViewMode.SETTINGS_ROOM:
      return <RoomInventory floors={props.floors} roomTypes={props.roomTypes} onAdd={props.onAddRoom} />;
    default:
      return <AdminMenu setViewMode={setViewMode} />;
  }
};

export default RoomSettings;

