import React from 'react';
import { Room, RoomType } from '../types';
import { ICONS } from '../constants';

interface RoomCardProps {
  room: Room;
  roomType?: RoomType;
  onClick: (room: Room) => void;
}

const RoomCard: React.FC<RoomCardProps> = ({ room, roomType, onClick }) => {
  if (room.isNonRoom) {
    return (
      <div className="bg-slate-200 border border-slate-300 rounded shadow-sm h-24 flex items-center justify-center cursor-not-allowed grayscale opacity-60">
        <div className="text-center">
          <div className="text-slate-500 font-bold text-sm">{room.roomNo}</div>
          <div className="text-slate-400 text-[10px] uppercase tracking-wider font-bold">Utility Area</div>
        </div>
      </div>
    );
  }

  // Mandatory Status Color Mapping:
  // Green -> Available
  // Red -> Occupied
  // Yellow -> Hold (Reserved/Cleaning/Hold)
  const statusColors = {
    Available: 'border-r-green-500',
    Occupied: 'border-r-red-500',
    Hold: 'border-r-yellow-500',
  };

  const borderColorClass = statusColors[room.status] || 'border-r-slate-300';

  return (
    <button
      onClick={() => onClick(room)}
      className={`bg-white border border-slate-200 border-r-4 ${borderColorClass} rounded shadow-sm hover:shadow-md hover:border-blue-400 transition-all h-24 p-3 flex flex-col justify-between text-left group`}
    >
      <div className="flex justify-between items-start">
        <span className="text-lg font-black text-slate-800 group-hover:text-blue-600 transition-colors">
          {room.roomNo}
        </span>
        <span className="text-[10px] font-bold bg-slate-100 text-slate-500 px-1.5 py-0.5 rounded border border-slate-200 tracking-tighter">
          {roomType?.name || '??'}
        </span>
      </div>

      <div className="flex items-center gap-2 mt-auto">
        {room.isSmoking && (
          <div title="Smoking Allowed">
            <ICONS.Smoking className="text-slate-400 w-3.5 h-3.5" />
          </div>
        )}
        {room.isHandicap && (
          <div title="Handicap Accessible">
            <ICONS.Handicap className="text-slate-400 w-3.5 h-3.5" />
          </div>
        )}
      </div>
    </button>
  );
};

export default RoomCard;

import React, { useState } from 'react';
import { Floor, Room, RoomType, ViewMode, RoomStatus } from '../types';
import { ICONS } from '../constants';

interface RoomSettingsProps {
  viewMode: ViewMode;
  setViewMode: (mode: ViewMode) => void;
  floors: Floor[];
  roomTypes: RoomType[];
  onAddFloor: (name: string) => void;
  onAddRoomType: (name: string, price: number) => void;
  onAddRoom: (room: Omit<Room, 'id'>) => void;
}

const FloorSetup: React.FC<{ floors: Floor[], onAddFloor: (n: string) => void }> = ({ floors, onAddFloor }) => {
  const [name, setName] = useState('');
  return (
    <div className="p-10 max-w-3xl mx-auto">
      <div className="bg-white p-10 rounded-xl border border-slate-200 shadow-xl shadow-slate-200/50">
        <div className="mb-8 border-b border-slate-100 pb-6">
          <h2 className="text-2xl font-extrabold text-slate-800">Floor Architecture</h2>
          <p className="text-sm text-slate-500 mt-1">Define property levels and spatial hierarchy.</p>
        </div>

        <form onSubmit={(e) => { e.preventDefault(); if(name) { onAddFloor(name); setName(''); }}} className="flex gap-3 mb-10">
          <input
            type="text"
            placeholder="Floor Designation (e.g. Lobby, Level 1)"
            value={name}
            onChange={(e) => setName(e.target.value)}
            className="flex-1 px-4 py-3 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none transition-all"
          />
          <button type="submit" className="bg-slate-900 text-white px-8 py-3 rounded-lg text-sm font-bold hover:bg-black transition-all shadow-md uppercase tracking-wider">
            Add
          </button>
        </form>

        <div className="border border-slate-100 rounded-xl bg-slate-50/30 overflow-hidden">
