interface DashboardProps {
  floors: Floor[];
  roomTypes: RoomType[];
  rooms: Room[];
  activeFloorId: string | null;
  onSelectFloor: (id: string | null) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  floors, 
  roomTypes, 
  rooms, 
  activeFloorId, 
  onSelectFloor 
}) => {
  const [selectedRoom, setSelectedRoom] = useState<Room | null>(null);

  const filteredRooms = activeFloorId 
    ? rooms.filter(r => r.floorId === activeFloorId)
    : rooms;

  return (
    <div className="flex flex-col h-full">
      {/* Floor Filter Bar - Corrected for Mandatory Requirements */}
      <div className="bg-white border-b border-slate-200 px-8 py-4 flex items-center gap-4 shadow-sm z-10">
        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em] mr-2">Property Levels:</span>
        <div className="flex flex-wrap gap-2">
          {floors.map(floor => (
            <button
              key={floor.id}
              onClick={() => onSelectFloor(activeFloorId === floor.id ? null : floor.id)}
              className={`px-5 py-1.5 rounded-md text-xs font-bold border transition-all tracking-tight ${
                activeFloorId === floor.id 
                ? 'bg-blue-600 text-white border-blue-600 shadow-md shadow-blue-100 scale-[1.02]' 
                : 'bg-white text-slate-500 border-slate-200 hover:border-blue-400 hover:text-blue-600'
              }`}
            >
              Floor {floor.name}
            </button>
          ))}
        </div>
      </div>

      {/* Main Room Grid */}
      <div className="flex-1 overflow-y-auto p-8">
        <div className="mb-6 flex items-center justify-between">
            <h2 className="text-sm font-black text-slate-800 uppercase tracking-widest">
                {activeFloorId ? `Floor ${floors.find(f => f.id === activeFloorId)?.name} Status` : 'Full Property Inventory'}
            </h2>
            <div className="flex gap-4">
                <div className="flex items-center gap-1.5">
                    <span className="w-2 h-2 rounded-full bg-green-500"></span>
                    <span className="text-[10px] font-bold text-slate-400 uppercase">Available</span>
                </div>
                <div className="flex items-center gap-1.5">
                    <span className="w-2 h-2 rounded-full bg-red-500"></span>
                    <span className="text-[10px] font-bold text-slate-400 uppercase">Occupied</span>
                </div>
                <div className="flex items-center gap-1.5">
                    <span className="w-2 h-2 rounded-full bg-yellow-500"></span>
                    <span className="text-[10px] font-bold text-slate-400 uppercase">Hold</span>
                </div>
            </div>
        </div>

        {filteredRooms.length === 0 ? (
          <div className="h-64 flex flex-col items-center justify-center text-slate-300 space-y-3 bg-white rounded-xl border border-dashed border-slate-200">
            <svg xmlns="http://www.w3.org/2000/svg" width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>
            <p className="text-sm font-medium">No units allocated for this selection.</p>
          </div>
        ) : (
          <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 xl:grid-cols-8 gap-4">
            {filteredRooms.map(room => (
              <RoomCard 
                key={room.id} 
                room={room} 
                roomType={roomTypes.find(rt => rt.id === room.roomTypeId)}
                onClick={(r) => !r.isNonRoom && setSelectedRoom(r)}
              />
            ))}
          </div>
        )}
      </div>

      <RoomDetailModal 
        room={selectedRoom}
        roomType={roomTypes.find(rt => rt.id === selectedRoom?.roomTypeId)}
        onClose={() => setSelectedRoom(null)}
      />
    </div>
  );
};

