const FloorSetup: React.FC<{ 
  floors: Floor[], 
  onAdd: (n: string) => void, 
  onUpdate: (id: string, n: string) => void,
  onDelete: (id: string) => void 
}> = ({ floors, onAdd, onUpdate, onDelete }) => {
  const [name, setName] = useState('');
  const [editingId, setEditingId] = useState<string | null>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim()) return;
    if (editingId) {
      onUpdate(editingId, name.trim());
      setEditingId(null);
    } else {
      onAdd(name.trim());
    }
    setName('');
  };

  const startEdit = (f: Floor) => {
    setEditingId(f.id);
    setName(f.name);
  };

  return (
    <div className="p-10 max-w-3xl mx-auto">
      <div className="bg-white p-10 rounded-xl border border-slate-200 shadow-xl">
        <div className="mb-8 border-b border-slate-100 pb-6">
          <h2 className="text-2xl font-black text-slate-800 uppercase tracking-tight">Floor Management</h2>
          <p className="text-sm text-slate-500 mt-1">Configure property levels and spatial structure.</p>
        </div>

        <form onSubmit={handleSubmit} className="flex gap-3 mb-10">
          <input
            type="text"
            required
            placeholder="Floor Name / Number"
            value={name}
            onChange={(e) => setName(e.target.value)}
            className="flex-1 px-4 py-3 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none transition-all"
          />
          <button type="submit" className="bg-slate-900 text-white px-8 py-3 rounded-lg text-sm font-bold hover:bg-black transition-all shadow-md uppercase tracking-wider">
            {editingId ? 'Update' : 'Add Floor'}
          </button>
          {editingId && (
            <button onClick={() => { setEditingId(null); setName(''); }} type="button" className="bg-slate-100 text-slate-600 px-6 py-3 rounded-lg text-sm font-bold">Cancel</button>
          )}
        </form>

        <div className="border border-slate-100 rounded-xl overflow-hidden bg-white">
          <div className="bg-slate-50 px-6 py-3 border-b border-slate-100 flex justify-between">
            <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Configured Levels</span>
          </div>
          <div className="divide-y divide-slate-50 max-h-[400px] overflow-y-auto">
            {floors.map(f => (
              <div key={f.id} className="px-6 py-4 flex items-center justify-between hover:bg-slate-50/50 transition-colors">
                <button onClick={() => startEdit(f)} className="text-slate-400 hover:text-blue-600 p-2 transition-colors">
                  <EditIcon />
                </button>
                <div className="flex-1 px-4">
                  <span className="text-sm font-bold text-slate-800">Floor {f.name}</span>
                </div>
                <button onClick={() => onDelete(f.id)} className="text-slate-300 hover:text-red-600 p-2 transition-colors">
                  <TrashIcon />
                </button>
              </div>
            ))}
            {floors.length === 0 && <div className="p-10 text-center text-slate-400 text-xs italic">No floors defined.</div>}
          </div>
        </div>
