const RoomTypeSetup: React.FC<{ 
  roomTypes: RoomType[], 
  onAdd: (n: string, p: number) => void,
  onUpdate: (id: string, n: string, p: number) => void,
  onDelete: (id: string) => void
}> = ({ roomTypes, onAdd, onUpdate, onDelete }) => {
  const [name, setName] = useState('');
  const [price, setPrice] = useState(0);
  const [editingId, setEditingId] = useState<string | null>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim() || price <= 0) return;
    if (editingId) {
      onUpdate(editingId, name.trim(), price);
      setEditingId(null);
    } else {
      onAdd(name.trim(), price);
    }
    setName('');
    setPrice(0);
  };

  const startEdit = (rt: RoomType) => {
    setEditingId(rt.id);
    setName(rt.name);
    setPrice(rt.defaultPrice);
  };

  return (
    <div className="p-10 max-w-4xl mx-auto">
      <div className="bg-white p-10 rounded-xl border border-slate-200 shadow-xl">
        <div className="mb-8 border-b border-slate-100 pb-6">
          <h2 className="text-2xl font-black text-slate-800 uppercase tracking-tight">Room Categories</h2>
          <p className="text-sm text-slate-500 mt-1">Define revenue classes and standard pricing.</p>
        </div>

        <form onSubmit={handleSubmit} className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-10 bg-slate-50 p-6 rounded-xl border border-slate-100">
          <div>
            <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest block mb-1">Type Code</label>
            <input required type="text" value={name} onChange={e => setName(e.target.value)} placeholder="e.g. DLX, STE" className="w-full px-4 py-3 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none" />
          </div>
          <div>
            <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest block mb-1">Standard Rate ($)</label>
            <input required type="number" value={price || ''} onChange={e => setPrice(Number(e.target.value))} placeholder="0.00" className="w-full px-4 py-3 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none" />
          </div>
          <div className="flex items-end gap-2">
            <button type="submit" className="flex-1 bg-blue-600 text-white py-3 rounded-lg text-sm font-bold hover:bg-blue-700 transition-all shadow-md uppercase tracking-wider">
              {editingId ? 'Update' : 'Add Category'}
            </button>
            {editingId && (
              <button onClick={() => { setEditingId(null); setName(''); setPrice(0); }} type="button" className="bg-slate-200 px-4 py-3 rounded-lg text-xs font-bold">X</button>
            )}
          </div>
        </form>

        <div className="border border-slate-100 rounded-xl overflow-hidden bg-white">
          <div className="divide-y divide-slate-50 max-h-[400px] overflow-y-auto">
            {roomTypes.map(rt => (
              <div key={rt.id} className="px-6 py-4 flex items-center justify-between hover:bg-slate-50 transition-colors">
                <button onClick={() => startEdit(rt)} className="text-slate-400 hover:text-blue-600 p-2">
                  <EditIcon />
                </button>
                <div className="flex-1 px-6 flex justify-between">
                   <span className="text-sm font-black text-slate-800">{rt.name}</span>
                   <span className="text-sm font-bold text-blue-600">${rt.defaultPrice.toFixed(2)}</span>
                </div>
                <button onClick={() => onDelete(rt.id)} className="text-slate-300 hover:text-red-600 p-2">
                  <TrashIcon />
                </button>
              </div>
            ))}
            {roomTypes.length === 0 && <div className="p-10 text-center text-slate-400 text-xs italic">No categories defined.</div>}
          </div>
        </div>
      </div>
    </div>
  );
};

const RoomInventory: React.FC<{ 
  floors: Floor[], 
  roomTypes: RoomType[], 
  rooms: Room[],
  onAdd: (r: Omit<Room, 'id'>) => void,
  onUpdate: (id: string, r: Omit<Room, 'id'>) => void,
  onDelete: (id: string) => void
}> = ({ floors, roomTypes, rooms, onAdd, onUpdate, onDelete }) => {
  const [no, setNo] = useState('');
  const [floorId, setFloorId] = useState('');
  const [roomTypeId, setRoomTypeId] = useState('');
  const [status, setStatus] = useState<RoomStatus>('Available');
  const [smoking, setSmoking] = useState(false);
  const [handicap, setHandicap] = useState(false);
  const [nonRoom, setNonRoom] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);

  useEffect(() => {
    if (floors.length > 0 && !floorId) setFloorId(floors[0].id);
    if (roomTypes.length > 0 && !roomTypeId) setRoomTypeId(roomTypes[0].id);
  }, [floors, roomTypes]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!no.trim() || !floorId || !roomTypeId) return;

    const data = { 
      roomNo: no.trim(), 
      floorId, 
      roomTypeId, 
      isSmoking: nonRoom ? false : smoking, 
      isHandicap: nonRoom ? false : handicap, 
      isNonRoom: nonRoom, 
      status 
    };

    if (editingId) {
      onUpdate(editingId, data);
      setEditingId(null);
    } else {
      onAdd(data);
    }
    resetForm();
  };

  const resetForm = () => {
    setNo('');
    setSmoking(false);
    setHandicap(false);
    setNonRoom(false);
    setStatus('Available');
    setEditingId(null);
  };

  const startEdit = (r: Room) => {
    setEditingId(r.id);
    setNo(r.roomNo);
    setFloorId(r.floorId);
    setRoomTypeId(r.roomTypeId);
    setSmoking(r.isSmoking);
    setHandicap(r.isHandicap);
    setNonRoom(r.isNonRoom);
    setStatus(r.status);
  };

  return (
    <div className="p-10 max-w-5xl mx-auto">
      <div className="bg-white p-10 rounded-xl border border-slate-200 shadow-xl mb-10">
        <div className="mb-8 border-b border-slate-100 pb-6">
          <h2 className="text-2xl font-black text-slate-800 uppercase tracking-tight">Inventory Registry</h2>
          <p className="text-sm text-slate-500 mt-1">Manage physical units and service locations.</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="grid grid-cols-1 sm:grid-cols-4 gap-6">
            <div>
              <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest block mb-1">Unit No.</label>
              <input required value={no} onChange={e => setNo(e.target.value)} placeholder="e.g. 101" className="w-full px-4 py-3 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none" />
            </div>
            <div>
              <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest block mb-1">Level</label>
              <select required value={floorId} onChange={e => setFloorId(e.target.value)} className="w-full px-4 py-3 border border-slate-300 rounded-lg text-sm bg-white focus:ring-2 focus:ring-blue-500">
                {floors.map(f => <option key={f.id} value={f.id}>Floor {f.name}</option>)}
              </select>
            </div>
            <div>
              <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest block mb-1">Category</label>
              <select required value={roomTypeId} onChange={e => setRoomTypeId(e.target.value)} className="w-full px-4 py-3 border border-slate-300 rounded-lg text-sm bg-white focus:ring-2 focus:ring-blue-500">
                {roomTypes.map(rt => <option key={rt.id} value={rt.id}>{rt.name}</option>)}
              </select>
            </div>
            <div>
              <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest block mb-1">Status</label>
              <select value={status} onChange={e => setStatus(e.target.value as RoomStatus)} className="w-full px-4 py-3 border border-slate-300 rounded-lg text-sm bg-white focus:ring-2 focus:ring-blue-500">
                <option value="Available">Available</option>
                <option value="Occupied">Occupied</option>
                <option value="Hold">Hold</option>
              </select>
            </div>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
            <label className={`flex items-center gap-3 p-4 rounded-xl border cursor-pointer transition-all ${nonRoom ? 'opacity-30' : ''}`}>
              <input type="checkbox" checked={smoking} disabled={nonRoom} onChange={e => setSmoking(e.target.checked)} className="w-5 h-5 text-blue-600 rounded" />
              <span className="text-sm font-bold text-slate-700">Smoking</span>
            </label>
            <label className={`flex items-center gap-3 p-4 rounded-xl border cursor-pointer transition-all ${nonRoom ? 'opacity-30' : ''}`}>
              <input type="checkbox" checked={handicap} disabled={nonRoom} onChange={e => setHandicap(e.target.checked)} className="w-5 h-5 text-blue-600 rounded" />
              <span className="text-sm font-bold text-slate-700">ADA / Handicap</span>
            </label>
            <label className="flex items-center gap-3 p-4 rounded-xl border border-red-100 bg-red-50/30 cursor-pointer transition-all">
              <input type="checkbox" checked={nonRoom} onChange={e => setNonRoom(e.target.checked)} className="w-5 h-5 text-red-600 rounded" />
              <span className="text-sm font-black text-red-700">Non-Room Entity</span>
            </label>
          </div>

          <div className="flex justify-end pt-4 gap-3">
            {editingId && <button onClick={resetForm} type="button" className="px-10 py-4 rounded-xl font-bold bg-slate-100 text-slate-600 uppercase tracking-widest text-sm">Cancel</button>}
            <button type="submit" className="bg-slate-900 text-white px-12 py-4 rounded-xl font-black shadow-lg hover:bg-black transition-all text-sm uppercase tracking-widest">
              {editingId ? 'Update Inventory' : 'Commit Registry'}
            </button>
          </div>
        </form>
      </div>

      <div className="bg-white rounded-xl border border-slate-200 overflow-hidden shadow-sm">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Edit</th>
              <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Unit #</th>
              <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Floor</th>
              <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Category</th>
              <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Status</th>
              <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Action</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {rooms.map(r => (
              <tr key={r.id} className="hover:bg-slate-50/50 transition-colors">
                <td className="px-6 py-4">
                  <button onClick={() => startEdit(r)} className="text-slate-400 hover:text-blue-600 transition-colors">
                    <EditIcon />
                  </button>
                </td>
                <td className="px-6 py-4 font-black text-slate-900">{r.roomNo}</td>
                <td className="px-6 py-4 text-sm text-slate-600">Floor {floors.find(f => f.id === r.floorId)?.name}</td>
                <td className="px-6 py-4 text-sm font-bold text-blue-600">{roomTypes.find(rt => rt.id === r.roomTypeId)?.name}</td>
                <td className="px-6 py-4">
                  <span className={`text-[10px] font-bold px-2 py-1 rounded uppercase ${
                    r.status === 'Available' ? 'bg-green-100 text-green-700' : 
                    r.status === 'Occupied' ? 'bg-red-100 text-red-700' : 'bg-yellow-100 text-yellow-700'
                  }`}>
                    {r.status}
                  </span>
                </td>
                <td className="px-6 py-4 text-right">
                  <button onClick={() => onDelete(r.id)} className="text-slate-300 hover:text-red-600 transition-colors">
                    <TrashIcon />
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

