            <input type="text" value={name} onChange={e => { setName(e.target.value); setError(''); }} placeholder="e.g. DLX, STE" className={`px-4 py-3 border rounded-lg text-sm font-bold outline-none transition-all ${error && !name.trim() ? 'border-red-500 bg-red-50' : 'border-slate-200 focus:border-blue-500 focus:ring-4 focus:ring-blue-50/50'}`} />
