                  <button onClick={() => { setEditingId(r.id); setNo(r.roomNo); setFloorId(r.floorId); setRoomTypeId(r.roomTypeId); setSmoking(r.isSmoking); setHandicap(r.isHandicap); setNonRoom(r.isNonRoom); setStatus(r.status); setError(''); }} className="text-slate-400 hover:text-blue-600 transition-colors">
                    <EditIcon />
                  </button>
