                    <span className={`text-[9px] font-black px-2 py-1 rounded uppercase tracking-tighter ${
                      r.status === 'Available' ? 'bg-green-100 text-green-700' : 
                      r.status === 'Occupied' ? 'bg-red-100 text-red-700' : 'bg-yellow-100 text-yellow-700'
