            <button type="submit" className="bg-slate-900 text-white px-12 py-3 rounded-lg text-xs font-black uppercase tracking-widest hover:bg-black transition-all shadow-xl">
              {editingId ? 'Update Inventory' : 'Register Unit'}
            </button>
