  isSmoking: boolean;
  isHandicap: boolean;
  isNonRoom: boolean;
  status: RoomStatus;
}

export interface GuestReservation {
  roomNo: string;
  roomType: string;
  guestName: string;
  phone: string;
  email: string;
  address: string;
  idType: string;
  idNumber: string;
  checkIn: string;
  checkOut: string;
