export enum ViewMode {
  DASHBOARD = 'DASHBOARD',
  SETTINGS_MENU = 'SETTINGS_MENU',
  SETTINGS_FLOOR = 'SETTINGS_FLOOR',
  SETTINGS_ROOM_TYPE = 'SETTINGS_ROOM_TYPE',
  SETTINGS_ROOM = 'SETTINGS_ROOM',
  ROOM_DETAIL = 'ROOM_DETAIL'
}

import React from 'react';
import { Room, RoomType } from '../types';
import { ICONS } from '../constants';

interface RoomCardProps {
  room: Room;
  roomType?: RoomType;
  onClick: (room: Room) => void;
}

const RoomCard: React.FC<RoomCardProps> = ({ room, roomType, onClick }) => {
  if (room.isNonRoom) {
    return (
      <div className="bg-slate-200 border border-slate-300 rounded shadow-sm h-24 flex items-center justify-center cursor-not-allowed grayscale opacity-60">
        <div className="text-center">
          <div className="text-slate-500 font-bold text-sm">{room.roomNo}</div>
          <div className="text-slate-400 text-[10px] uppercase tracking-wider font-bold">Utility Area</div>
        </div>
      </div>
    );
  }

  // Mandatory Status Color Mapping:
  const statusColors = {
    Available: 'border-r-emerald-500',
    Occupied: 'border-r-rose-500',
    Dirty: 'border-r-amber-700',
    Clean: 'border-r-cyan-500',
    'Out of Order': 'border-r-slate-800',
    'Under Maintenance': 'border-r-indigo-600',
  };

  const borderColorClass = statusColors[room.status] || 'border-r-slate-300';

  return (
    <button
      onClick={() => onClick(room)}
      className={`bg-white border border-slate-200 border-r-4 ${borderColorClass} rounded shadow-sm hover:shadow-md hover:border-blue-400 transition-all h-24 p-3 flex flex-col justify-between text-left group`}
    >
      <div className="flex justify-between items-start">
        <span className="text-lg font-black text-slate-800 group-hover:text-blue-600 transition-colors">
          {room.roomNo}
        </span>
        <span className="text-[10px] font-bold bg-slate-100 text-slate-500 px-1.5 py-0.5 rounded border border-slate-200 tracking-tighter">
          {roomType?.name || '??'}
        </span>
      </div>

      <div className="flex items-center gap-2 mt-auto">
        {room.isSmoking && (
          <div title="Smoking Allowed">
            <ICONS.Smoking className="text-slate-400 w-3.5 h-3.5" />
          </div>
        )}
        {room.isHandicap && (
          <div title="Handicap Accessible">
            <ICONS.Handicap className="text-slate-400 w-3.5 h-3.5" />
          </div>
        )}
      </div>
    </button>
  );
};

export default RoomCard;

import React from 'react';
import { Floor, Room, RoomType } from '../types';
import RoomCard from './RoomCard';

interface DashboardProps {
  floors: Floor[];
  roomTypes: RoomType[];
  rooms: Room[];
  activeFloorId: string | null;
  onSelectFloor: (id: string | null) => void;
  onSelectRoom: (room: Room) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  floors, 
  roomTypes, 
  rooms, 
  activeFloorId, 
  onSelectFloor,
  onSelectRoom
}) => {
  const filteredRooms = activeFloorId 
    ? rooms.filter(r => r.floorId === activeFloorId)
    : rooms;

  // Sorting: Floors must always appear in numeric order
  const sortedFloors = [...floors].sort((a, b) => Number(a.name) - Number(b.name));

