        <div className="flex gap-4 overflow-x-auto no-scrollbar py-2">
          {sortedFloors.map(floor => (
            <button
              key={floor.id}
              onClick={() => onSelectFloor(activeFloorId === floor.id ? null : floor.id)}
              className={`group relative min-w-[80px] h-20 flex flex-col items-center justify-center rounded-xl border-2 transition-all duration-300 outline-none ${
                activeFloorId === floor.id 
                ? 'bg-blue-600 border-blue-700 text-white shadow-xl shadow-blue-200 translate-y-[-2px]' 
                : 'bg-white border-slate-100 text-slate-400 hover:border-blue-200 hover:text-blue-600 hover:bg-blue-50/30'
              }`}
            >
              <span className={`text-[10px] font-black uppercase tracking-widest mb-1 transition-colors ${activeFloorId === floor.id ? 'text-blue-100' : 'text-slate-300 group-hover:text-blue-400'}`}>Floor</span>
