                room={room} 
                roomType={roomTypes.find(rt => rt.id === room.roomTypeId)}
                onClick={(r) => !r.isNonRoom && onSelectRoom(r)}
              />
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

